import React from 'react'
import axios from 'axios';
import { useEffect, useState } from 'react';
import { useNavigate } from "react-router-dom";

function rowAction () {
    alert("Clicked!")
}

function Items() {
    const navigate = useNavigate();
    const [listOfItems, setListOfItems] = useState([]);

    const [addItemVisible, setAddItemVisible] = useState(false);

    useEffect(() => {
        axios.get("http://localhost:3001/items", { headers: { accessToken: localStorage.getItem("accessToken") } }).then((response) => {
            if (response.data.error) navigate("/login");
            else setListOfItems(response.data);
        })
    }, []);

    const listItems = listOfItems.map((value, key) => 
        <tr key={key} onClick={rowAction} class="hover:bg-cyan-200 cursor-pointer *:border-collapse *:border-slate-300 border-slate-300 border-b-2 *:border-r-2">
            <td>{value.name}</td>
            <td>{value.description}</td>
            <td>{value.quantity}</td>
            <td class="border-none">{value.price}</td>
        </tr>
    );

    function handleNewItem (e) {
        e.preventDefault();
        setAddItemVisible(!addItemVisible);
        if (addItemVisible){
            alert(addItemVisible.toString());
        } else {
            alert(addItemVisible.toString());
        }
    }

    return (
        <div class="mx-auto flex w-full">
            <div class="items-start p-1">
                <button onClick={handleNewItem} className="bg-cyan-200 rounded-md hover:bg-cyan-300 active:bg-cyan-400 border-2 border-slate-400 p-1">
                    Add {!addItemVisible && "New"} Item
                </button>
                {addItemVisible && <div>Adding new item...</div>}
            </div>
            <div class="mx-auto items-center w-2/3 bg-cyan-100 p-1 rounded-xl shadow-lg outline outline-black/5">
                <table class="table w-full">
                    <thead>
                        <tr class="border-b-2 border-collapse border-slate-300">
                            <th class="rounded-md">Item</th>
                            <th class="rounded-md">Description</th>
                            <th class="rounded-md">Quantity</th>
                            <th class="rounded-md">Price($)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {listItems}
                    </tbody>
                </table>
            </div>
            <div class="p-1"></div>
        </div>
    )
}

export default Items
